import React, { useRef, useState } from 'react';
import Container from '../Container';
import './style.css';

export default function CountersPage() {
  const [counter, setCounter] = useState(0);
  const previousCounterRef = useRef(0);

  const handleDecrease = () => {
    previousCounterRef.current = counter;
    setCounter((prevCounter) => prevCounter - 1);
  };

  const handleIncrease = () => {
    previousCounterRef.current = counter;
    setCounter((prevCounter) => prevCounter + 1);
  };

  const handleReset = () => {
    previousCounterRef.current = counter;
    setCounter(0);
  };

  return (
    <Container>
      <main className="counters-page">
        <section className="counter-panel">
          <p className="counter-kicker">Interactive Counter</p>
          <h1>Counters Page</h1>
          <p className="counter-description">
            This example uses <code>useState</code> for the current value and <code>useRef</code>
            to remember the previous one.
          </p>

          <div className="counter-display">
            <span>{counter}</span>
          </div>

          <div className="counter-history">
            <div className="counter-history-card">
              <p>Current</p>
              <strong>{counter}</strong>
            </div>
            <div className="counter-history-card">
              <p>Previous</p>
              <strong>{previousCounterRef.current}</strong>
            </div>
          </div>

          <div className="counter-actions">
            <button onClick={handleDecrease} className="counter-button secondary">
              Decrease
            </button>
            <button onClick={handleIncrease} className="counter-button primary">
              Increase
            </button>
          </div>

          <div className="counter-reset-row">
            <button onClick={handleReset} className="counter-button neutral">
              Reset
            </button>
          </div>
        </section>
      </main>
    </Container>
  );
}
